-- ============================================================
-- SEED DATA: DOANH_THU – dữ liệu mẫu 60 ngày (kỳ này + kỳ trước)
-- Yêu cầu: CHI_NHANH CN-1..CN-10 phải tồn tại
-- Ngày gốc: 2026-05-14
-- ============================================================

-- Drop + Tạo lại bảng DOANH_THU
BEGIN EXECUTE IMMEDIATE 'DROP TABLE DOANH_THU CASCADE CONSTRAINTS'; EXCEPTION WHEN OTHERS THEN NULL; END;
/

CREATE TABLE DOANH_THU
(
    MADT          VARCHAR2(20),
    MACN          VARCHAR2(20),
    LOAI          VARCHAR2(10),
    NOIDUNG       VARCHAR2(255),
    NGAY          DATE,
    NGAY_BAT_DAU  DATE,
    NGAY_KET_THUC DATE,
    DT_THUE_SAN   NUMBER(12, 2) DEFAULT 0,
    DT_DICH_VU    NUMBER(12, 2) DEFAULT 0,
    TONGDOANHTHU  NUMBER(12, 2),
    CREATED_AT    DATE      DEFAULT SYSDATE NOT NULL,
    IS_DELETED    NUMBER(1) DEFAULT 0       NOT NULL,
    CONSTRAINT PK_DOANH_THU PRIMARY KEY (MADT),
    CONSTRAINT FK_DOANH_THU_CHI_NHANH FOREIGN KEY (MACN) REFERENCES CHI_NHANH (MACN),
    CONSTRAINT CK_DOANH_THU_IS_DELETED CHECK (IS_DELETED IN (0, 1)),
    CONSTRAINT CK_DOANH_THU_LOAI CHECK (LOAI IN ('NGAY', 'TUAN', 'THANG', 'NAM'))
);

